//! Broadcast coordinator for cancellation signals.

use std::collections::{HashMap, HashSet};
use std::sync::{Arc, RwLock};
use crate::error::Result;

/// Coordinates cancellation broadcast across peers.
pub struct CancelBroadcaster {
    /// Known peers.
    peers: RwLock<Vec<PeerId>>,
    /// Active cancellation tokens by object ID.
    active_tokens: RwLock<HashMap<ObjectId, SymbolCancelToken>>,
    /// Seen message sequences for deduplication.
    seen_sequences: RwLock<HashSet<(u64, u64)>>, // (token_id, sequence)
    /// Maximum seen sequences to retain.
    max_seen: usize,
    /// Broadcast sink for sending messages.
    sink: Arc<dyn CancelSink>,
    /// Local sequence counter.
    next_sequence: AtomicU64,
    /// Metrics.
    metrics: CancelBroadcastMetrics,
}

/// Trait for sending cancellation messages.
pub trait CancelSink: Send + Sync {
    /// Sends a cancellation message to a specific peer.
    fn send_to(&self, peer: &PeerId, msg: &CancelMessage) -> impl Future<Output = Result<()>> + Send;

    /// Broadcasts a cancellation message to all peers.
    fn broadcast(&self, msg: &CancelMessage) -> impl Future<Output = Result<usize>> + Send;
}

/// Peer identifier.
#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub struct PeerId(String);

impl PeerId {
    /// Creates a new peer ID.
    #[must_use]
    pub fn new(id: impl Into<String>) -> Self {
        Self(id.into())
    }

    /// Returns the ID as a string slice.
    #[must_use]
    pub fn as_str(&self) -> &str {
        &self.0
    }
}

/// Metrics for cancellation broadcast.
#[derive(Clone, Debug, Default)]
pub struct CancelBroadcastMetrics {
    /// Cancellations initiated locally.
    pub initiated: u64,
    /// Cancellations received from peers.
    pub received: u64,
    /// Cancellations forwarded to peers.
    pub forwarded: u64,
    /// Duplicate cancellations ignored.
    pub duplicates: u64,
    /// Cancellations that reached max hops.
    pub max_hops_reached: u64,
}

impl CancelBroadcaster {
    /// Creates a new broadcaster.
    pub fn new(sink: Arc<dyn CancelSink>) -> Self {
        Self {
            peers: RwLock::new(Vec::new()),
            active_tokens: RwLock::new(HashMap::new()),
            seen_sequences: RwLock::new(HashSet::new()),
            max_seen: 10_000,
            sink,
            next_sequence: AtomicU64::new(0),
            metrics: CancelBroadcastMetrics::default(),
        }
    }

    /// Registers a peer.
    pub fn add_peer(&self, peer: PeerId) {
        let mut peers = self.peers.write().expect("lock poisoned");
        if !peers.contains(&peer) {
            peers.push(peer);
        }
    }

    /// Removes a peer.
    pub fn remove_peer(&self, peer: &PeerId) {
        let mut peers = self.peers.write().expect("lock poisoned");
        peers.retain(|p| p != peer);
    }

    /// Registers a cancellation token for an object.
    pub fn register_token(&self, token: SymbolCancelToken) {
        self.active_tokens
            .write()
            .expect("lock poisoned")
            .insert(token.object_id(), token);
    }

    /// Unregisters a token.
    pub fn unregister_token(&self, object_id: &ObjectId) {
        self.active_tokens
            .write()
            .expect("lock poisoned")
            .remove(object_id);
    }

    /// Initiates cancellation and broadcasts to peers.
    pub async fn cancel(
        &self,
        object_id: ObjectId,
        reason: CancelReason,
        now: Time,
    ) -> Result<usize> {
        // Cancel local token
        if let Some(token) = self.active_tokens.read().expect("lock poisoned").get(&object_id) {
            token.cancel(reason.clone(), now);
        }

        // Create message
        let sequence = self.next_sequence.fetch_add(1, Ordering::SeqCst);
        let msg = CancelMessage::new(
            // Use object ID as token ID for simplicity
            object_id.as_u128() as u64,
            object_id,
            reason.kind(),
            now,
            sequence,
        );

        // Mark as seen
        self.mark_seen(msg.token_id(), sequence);

        // Broadcast
        let count = self.sink.broadcast(&msg).await?;

        // Update metrics
        self.metrics.initiated += 1;

        Ok(count)
    }

    /// Handles a received cancellation message.
    pub async fn handle_message(&self, msg: CancelMessage, now: Time) -> Result<()> {
        // Check for duplicate
        if self.is_seen(msg.token_id(), msg.sequence()) {
            self.metrics.duplicates += 1;
            return Ok(());
        }

        // Mark as seen
        self.mark_seen(msg.token_id(), msg.sequence());

        // Update metrics
        self.metrics.received += 1;

        // Cancel local token if present
        if let Some(token) = self
            .active_tokens
            .read()
            .expect("lock poisoned")
            .get(&msg.object_id())
        {
            let reason = CancelReason::new(msg.kind());
            token.cancel(reason, now);
        }

        // Forward if allowed
        if let Some(forwarded) = msg.forwarded() {
            let count = self.sink.broadcast(&forwarded).await?;
            if count > 0 {
                self.metrics.forwarded += 1;
            }
        } else {
            self.metrics.max_hops_reached += 1;
        }

        Ok(())
    }

    /// Returns current metrics.
    #[must_use]
    pub fn metrics(&self) -> CancelBroadcastMetrics {
        self.metrics.clone()
    }

    fn is_seen(&self, token_id: u64, sequence: u64) -> bool {
        self.seen_sequences
            .read()
            .expect("lock poisoned")
            .contains(&(token_id, sequence))
    }

    fn mark_seen(&self, token_id: u64, sequence: u64) {
        let mut seen = self.seen_sequences.write().expect("lock poisoned");
        seen.insert((token_id, sequence));

        // Evict old entries if needed
        if seen.len() > self.max_seen {
            // Simple eviction: remove half the entries
            let to_remove: Vec<_> = seen.iter().take(self.max_seen / 2).cloned().collect();
            for key in to_remove {
                seen.remove(&key);
            }
        }
    }
}
